import java.io.IOException;
import java.util.StringTokenizer;

import org.apache.hadoop.conf.Configuration;
import org.apache.hadoop.fs.Path;
import org.apache.hadoop.io.IntWritable;
import org.apache.hadoop.io.Text;
import org.apache.hadoop.mapreduce.Job;
import org.apache.hadoop.mapreduce.Mapper;
import org.apache.hadoop.mapreduce.Reducer;
import org.apache.hadoop.mapreduce.lib.input.FileInputFormat;
import org.apache.hadoop.mapreduce.lib.output.FileOutputFormat;

/**
 * Word Count MapReduce Job - Classic Example
 * Counts occurrences of each word in input text files
 * 
 * Input: Text files from HDFS
 * Output: (word, count) pairs sorted alphabetically
 */
public class WordCount {

    // ==================== MAPPER CLASS ====================
    /**
     * Mapper class: Takes input lines and produces intermediate key-value pairs
     * Input Key: LongWritable (byte offset in file)
     * Input Value: Text (one line of text)
     * Output Key: Text (word)
     * Output Value: IntWritable (count = 1)
     */
    public static class WordMapper extends Mapper<LongWritable, Text, Text, IntWritable> {

        private final static IntWritable ONE = new IntWritable(1);
        private Text word = new Text();

        @Override
        public void map(LongWritable key, Text value, Context context)
                throws IOException, InterruptedException {

            // Convert line to String
            String line = value.toString();

            // Tokenize by whitespace
            StringTokenizer tokenizer = new StringTokenizer(line);

            // Process each word in the line
            while (tokenizer.hasMoreTokens()) {
                word.set(tokenizer.nextToken());

                // Emit (word, 1) - each occurrence counts as 1
                context.write(word, ONE);
            }
        }
    }

    // ==================== REDUCER CLASS ====================
    /**
     * Reducer class: Aggregates counts for each unique word
     * Input Key: Text (word)
     * Input Value: Iterable<IntWritable> (list of 1s for each occurrence)
     * Output Key: Text (word)
     * Output Value: IntWritable (total count)
     */
    public static class IntSumReducer extends Reducer<Text, IntWritable, Text, IntWritable> {

        private IntWritable result = new IntWritable();

        @Override
        public void reduce(Text key, Iterable<IntWritable> values, Context context)
                throws IOException, InterruptedException {

            int sum = 0;

            // Iterate through all values (counts) for this key
            for (IntWritable val : values) {
                sum += val.get();
            }

            result.set(sum);

            // Emit (word, total_count)
            context.write(key, result);
        }
    }

    // ==================== MAIN DRIVER ====================
    /**
     * Main driver method to configure and submit the MapReduce job
     */
    public static void main(String[] args) throws Exception {

        // Check command line arguments
        if (args.length != 2) {
            System.err.println("Usage: WordCount <input path> <output path>");
            System.exit(-1);
        }

        // Get configuration
        Configuration conf = new Configuration();

        // Create and configure job
        Job job = Job.getInstance(conf, "word count");
        job.setJarByClass(WordCount.class);

        // Set mapper and reducer classes
        job.setMapperClass(WordMapper.class);
        job.setReducerClass(IntSumReducer.class);

        // Set output key-value types
        job.setOutputKeyClass(Text.class);
        job.setOutputValueClass(IntWritable.class);

        // Set input and output paths
        FileInputFormat.addInputPath(job, new Path(args[0]));
        FileOutputFormat.setOutputPath(job, new Path(args[1]));

        // Wait for job completion and exit with appropriate code
        System.exit(job.waitForCompletion(true) ? 0 : 1);
    }
}

/*
 * COMPLETE MAPREDUCE EXECUTION FLOW:
 * 
 * 1. INPUT: Text file "data.txt" stored in HDFS
 *    Line 1: "hello world hello"
 *    Line 2: "hadoop mapreduce"
 * 
 * 2. SPLIT PHASE:
 *    - File divided into input splits
 *    - Each split -> one map task
 * 
 * 3. MAP PHASE:
 *    Map Task 1 (Line 1):
 *      map(0, "hello world hello")
 *      -> ("hello", 1), ("world", 1), ("hello", 1)
 *    
 *    Map Task 2 (Line 2):
 *      map(18, "hadoop mapreduce")
 *      -> ("hadoop", 1), ("mapreduce", 1)
 * 
 * 4. SHUFFLE & SORT PHASE:
 *    - Group by key: ("hello" -> [1,1]), ("world" -> [1]), ("hadoop" -> [1]), ("mapreduce" -> [1])
 *    - Sort by key alphabetically
 * 
 * 5. REDUCE PHASE:
 *    Reducer 1: reduce("hello", [1,1]) -> ("hello", 2)
 *    Reducer 2: reduce("hadoop", [1]) -> ("hadoop", 1)
 *    Reducer 3: reduce("mapreduce", [1]) -> ("mapreduce", 1)
 *    Reducer 4: reduce("world", [1]) -> ("world", 1)
 * 
 * 6. OUTPUT (HDFS):
 *    part-r-00000:
 *      hadoop  1
 *      hello  2
 *      mapreduce      1
 *      world  1
 * 
 * COMPILATION AND RUN:
 * $ javac -cp $(hadoop classpath) WordCount.java
 * $ jar cf wordcount.jar WordCount*.class
 * $ hadoop jar wordcount.jar WordCount /input/path /output/path
 */

import java.io.IOException;
import java.util.Iterator;

import org.apache.hadoop.conf.Configuration;
import org.apache.hadoop.fs.Path;
import org.apache.hadoop.io.Text;
import org.apache.hadoop.mapreduce.Job;
import org.apache.hadoop.mapreduce.Mapper;
import org.apache.hadoop.mapreduce.Reducer;
import org.apache.hadoop.mapreduce.lib.input.FileInputFormat;
import org.apache.hadoop.mapreduce.lib.output.FileOutputFormat;

/**
 * IoT Device Status Aggregation MapReduce
 * Processes device log files to count devices by status
 * Uses Combiner for network optimization
 * 
 * Input Format: device_id,status,timestamp
 * Example: "device123,online,1705312800"
 * 
 * Output: (status, total_count) - e.g., (online, 1500), (offline, 50)
 */
public class DeviceStatusAggregator {

    // ==================== PARTITIONER CLASS ====================
    /**
     * Custom Partitioner: Routes keys to reducers based on status
     * Ensures all 'online' keys go to reducer 0, 'offline' to reducer 1
     */
    public static class StatusPartitioner extends 
            org.apache.hadoop.mapreduce.Partitioner<Text, Text> {

        @Override
        public int getPartition(Text key, Text value, int numReducers) {

            String status = key.toString();

            // Simple partition: 0 for online, 1 for offline
            if ("online".equals(status)) {
                return 0;
            } else {
                return 1;
            }
        }
    }

    // ==================== MAPPER CLASS ====================
    /**
     * Mapper: Parses device logs and emits (status, 1)
     * Input: (offset, "device_id,status,timestamp")
     * Output: (status, "1")
     */
    public static class DeviceMapper extends Mapper<Object, Text, Text, Text> {

        private Text statusKey = new Text();
        private Text countValue = new Text("1");

        @Override
        public void map(Object key, Text value, Context context)
                throws IOException, InterruptedException {

            // Parse: device_id,status,timestamp
            String line = value.toString();
            String[] fields = line.split(",");

            // Validate record format
            if (fields.length >= 2) {
                String status = fields[1];

                // Emit (status, "1") for counting
                statusKey.set(status);
                context.write(statusKey, countValue);

                System.out.println("Map: " + line + " -> (" + status + ", 1)");
            }
        }
    }

    // ==================== COMBINER CLASS ====================
    /**
     * Combiner: Local reduction at mapper node
     * Reduces network traffic by pre-aggregating counts locally
     * 
     * IMPORTANT: Combiners only work for associative/commutative operations
     * Addition satisfies both properties, so we can use a combiner
     */
    public static class StatusCombiner extends Reducer<Text, Text, Text, Text> {

        @Override
        public void reduce(Text key, Iterable<Text> values, Context context)
                throws IOException, InterruptedException {

            int localSum = 0;

            // Sum all local counts for this status
            Iterator<Text> iter = values.iterator();
            while (iter.hasNext()) {
                localSum += Integer.parseInt(iter.next().toString());
            }

            // Emit aggregated count
            context.write(key, new Text(String.valueOf(localSum)));

            System.out.println("Combiner: (" + key + ", [values]) -> (" + key + ", " + localSum + ")");
        }
    }

    // ==================== REDUCER CLASS ====================
    /**
     * Reducer: Aggregates all counts for each status
     * Input: (status, ["1", "1", "1", ...]) from all mappers
     * Output: (status, total_count)
     */
    public static class StatusReducer extends Reducer<Text, Text, Text, Text> {

        @Override
        public void reduce(Text key, Iterable<Text> values, Context context)
                throws IOException, InterruptedException {

            int totalCount = 0;

            // Sum all counts from all mappers
            Iterator<Text> iter = values.iterator();
            while (iter.hasNext()) {
                totalCount += Integer.parseInt(iter.next().toString());
            }

            // Emit final aggregated result
            context.write(key, new Text(String.valueOf(totalCount)));

            System.out.println("Reduce: (" + key + ", [values]) -> (" + key + ", " + totalCount + ")");
        }
    }

    // ==================== MAIN DRIVER ====================
    public static void main(String[] args) throws Exception {

        if (args.length != 2) {
            System.err.println("Usage: DeviceStatusAggregator <input> <output>");
            System.exit(-1);
        }

        Configuration conf = new Configuration();
        Job job = Job.getInstance(conf, "Device Status Aggregation");
        job.setJarByClass(DeviceStatusAggregator.class);

        // Set mapper, combiner, and reducer classes
        job.setMapperClass(DeviceMapper.class);
        job.setCombinerClass(StatusCombiner.class);  // OPTIMIZATION: Local aggregation
        job.setReducerClass(StatusReducer.class);

        // Set custom partitioner
        job.setPartitionerClass(StatusPartitioner.class);

        // Set number of reduce tasks (2: online and offline)
        job.setNumReduceTasks(2);

        // Set output types
        job.setOutputKeyClass(Text.class);
        job.setOutputValueClass(Text.class);

        // Set input and output paths
        FileInputFormat.addInputPath(job, new Path(args[0]));
        FileOutputFormat.setOutputPath(job, new Path(args[1]));

        // Submit job
        boolean success = job.waitForCompletion(true);

        System.out.println("\n=== Job Summary ===");
        System.out.println("Job ID: " + job.getJobID());
        System.out.println("Map Tasks: " + job.getNumMapTasks());
        System.out.println("Reduce Tasks: " + job.getNumReduceTasks());
        System.out.println("Status: " + (success ? "SUCCESS" : "FAILED"));

        System.exit(success ? 0 : 1);
    }
}

/*
 * EXECUTION EXAMPLE:
 * 
 * Input (HDFS): device_logs.txt
 *   device001,online,1705312800
 *   device002,online,1705312801
 *   device003,offline,1705312802
 *   device004,online,1705312803
 *   device005,offline,1705312804
 * 
 * MAP PHASE:
 *   Map 1: device001,online -> (online, 1)
 *   Map 1: device002,online -> (online, 1)
 *   Map 1: device003,offline -> (offline, 1)
 *   Map 1: device004,online -> (online, 1)
 *   Map 1: device005,offline -> (offline, 1)
 * 
 * COMBINER (runs on mapper node):
 *   Combiner 1: (online, [1,1,1]) -> (online, 3)
 *   Combiner 1: (offline, [1,1]) -> (offline, 2)
 * 
 * PARTITIONER:
 *   online -> Reducer 0
 *   offline -> Reducer 1
 * 
 * REDUCE PHASE:
 *   Reducer 0: (online, [3]) -> (online, 3)
 *   Reducer 1: (offline, [2]) -> (offline, 2)
 * 
 * OUTPUT (HDFS):
 *   part-r-00000: online   3
 *   part-r-00001: offline  2
 * 
 * WITHOUT COMBINER: 5 network transfers
 * WITH COMBINER: 2 network transfers (significant optimization for large datasets)
 */
